  ('elementary-e0adf6cd-moex-00319', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「科層體制」（bureaucracy）可能產生的負面功能之一為「若過度依表現升遷，則能者會升遷到一個無法 勝任的職位為止」，此即一般所稱的何種現象？', '["月暈效應（haloeffect）", "帕金森定律（Parkinson’slaw）", "彼得原理（Peterprinciple）", "寡頭鐵律（ironlawofoligarchy）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00320', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '分組合作學習教學法不具備下列何項特色？', '["有小老師制", "強調足夠的時間來達成精熟", "學生小組成就區分法（STAD）是策略之一", "共同合作相互支持提高個人學習成效並達團體目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00321', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '專題導向學習在我國教學現場開始受矚目，下列何位老師的運用方式或論述較不適切？', '["甲師--可將專題導向運用於所有學科的學習", "乙師--專題導向是一種以學生為中心的做中學取向", "丙師--主張專題導向有助於培養學生主動學習的能力", "丁師--在專題導向學習中以學生感興趣的真實性問題為核心"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00322', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '我國第一次參加「促進國際閱讀素養研究」（ProgressinInternationalReadingLiteracyStudy,PIRLS）的成 績中，教師問卷結果指出國小國語課老師較少進行下列何項指導工作？', '["閱讀理解策略指導", "學生習作指導", "字彙音義指導", "考試策略指導"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00323', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列何項不是教學活動設計的主要目的？', '["可作為教師評鑑的依據", "可使教師的教學有充分準備", "可作為教師編製評量測驗的依據", "可指出教學方向確保教學目標之實現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00324', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '實施生命教育時，生命意義的探尋與發現，對每位學生而言都是非常重要的。而弗蘭克（ViktorE.Frankl） 的意義治療學強調人們可以借由三種不同途徑去發現生命意義，分別是藉著創造與工作、體認價值以及下 列何者進行？', '["愛", "快樂", "成就", "受苦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00325', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '在班級經營中，如果教師允許一個學生的問題行為出現而不加以處理，其他學生的問題行為亦隨之而出， 此種情形稱之為下列何種效應？', '["天花板效應（ceilingeffect）", "地板效應（flooreffect）", "漣漪效應（rippleeffect）", "寒蟬效應（chillingeffect）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00326', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '一位有效能的教師，必須能夠組織教室環境裡的重要因素，以提供一個適合學生學習的情境，下列何項不 屬於前述之教室環境？', '["教室的照明設施", "學生課桌椅的擺設", "粉筆與板擦擺放的位置", "學習角的設計與安全考量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00327', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '教師在處理班上問題時，常會遭遇到因性別差異而產生的問題，其在處理此類問題時應注意之事項，下列 何者正確？', '["教師應注意性別平等之機會，因此應讓單一性別的學生有較多的表現機會", "不同性別學生都應鼓勵其盡量測試自己學習和成就的極限學習活動", "學生的性別差異是絕對的，且存在相當程度的差異", "學習活動應減少不同性別者互動的機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00328', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '依照綏勒（Saylor）技能層面的教育目標分類，從事技能的教學時，要求學生嘗試錯誤的歷程，是屬於下 列何種層次？', '["知覺", "心向", "模仿", "機械化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
